from flask import Flask, request, jsonify
from flask_sqlalchemy import SQLAlchemy
from sqlalchemy import func
import hashlib
import os

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///annotations.db'
db = SQLAlchemy(app)

class Annotation(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    image_id = db.Column(db.String(80), nullable=False)
    label = db.Column(db.String(80), nullable=False)
    annotator_id = db.Column(db.String(80), nullable=False)
    hash = db.Column(db.String(128), nullable=False)

db.create_all()

def generate_hash(data):
    return hashlib.sha256(data.encode()).hexdigest()

@app.route('/submit_label', methods=['POST'])
def submit_label():
    data = request.json
    image_id = data['image_id']
    label = data['label']
    annotator_id = data['annotator_id']
    
    label_hash = generate_hash(f"{image_id}-{label}-{annotator_id}")
    
    new_annotation = Annotation(image_id=image_id, label=label, annotator_id=annotator_id, hash=label_hash)
    db.session.add(new_annotation)
    db.session.commit()
    
    return jsonify({"message": "Label submitted successfully"}), 201

@app.route('/aggregate_labels/<image_id>', methods=['GET'])
def aggregate_labels(image_id):
    results = db.session.query(Annotation.label, func.count(Annotation.label)).filter(Annotation.image_id == image_id).group_by(Annotation.label).all()
    majority_label = max(results, key=lambda x: x[1])[0] if results else None
    
    return jsonify({"image_id": image_id, "majority_label": majority_label})

